mapper.select:
select ID as id, Cost_claims_year as costClaimsYear, N_claims_year as nClaimsYear, N_claims_history as nClaimsHistory, R_Claims_history as rClaimsHistory, Type_risk as typeRisk, Area as area from claim_record
and ID = #{id} and Type_risk = #{typeRisk} and Area = #{area}
order by ID desc
